<?php
namespace App\Modules\Hr\Advance\Actions;
use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Advance\Models\HrAdvance; use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Str;
class CreateAdvanceAction { public function __construct(private HrAuditService $audit){} public function execute(HrEmployee $employee,array $data,?string $sourceKey=null):HrAdvance{$tenant=app(TenantContext::class)->getId();abort_unless(auth()->user()?->hasHrPermission('hr.advances.create'),403);abort_unless($employee->legal_entity_id===$tenant,422);abort_unless($employee->user_id===auth()->id()||auth()->user()?->hasHrPermission('hr.advances.approve'),403);$amount=round((float)($data['requested_amount']??0),2);$installments=(int)($data['installment_count']??1);$currency=strtoupper($data['currency']??'TRY');$reason=trim((string)($data['reason']??''));$date=$data['requested_payment_date']??null;abort_if($amount<=0||$installments<1||$installments>36||blank($reason)||blank($date),422,'Avans bilgileri geçersiz.');abort_unless(in_array($currency,['TRY','EUR','USD','GBP'],true),422);$sourceKey??=(string)Str::uuid();abort_unless(Str::isUuid($sourceKey),422);$payload=['employee_id'=>$employee->id,'requested_amount'=>number_format($amount,2,'.',''),'currency'=>$currency,'installment_count'=>$installments,'requested_payment_date'=>$date,'reason'=>$reason];$hash=hash('sha256',json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_PRESERVE_ZERO_FRACTION));$existing=HrAdvance::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('source_key',$sourceKey)->first();if($existing){abort_unless(hash_equals($existing->payload_hash,$hash),409,'Kaynak anahtarı farklı avans içeriğiyle kullanılamaz.');return $existing;}$advance=HrAdvance::create([...$payload,'legal_entity_id'=>$tenant,'status'=>AdvanceStatus::PendingManager,'source_key'=>$sourceKey,'payload_hash'=>$hash,'requested_by'=>auth()->id()]);$this->audit->log('advance_created',$advance,null,['requested_amount'=>$amount,'currency'=>$currency]);return $advance;} }
